var hostname = location.hostname;
var STORAGE_KEY = 'domo_hiders_' + hostname;
var STYLE_ID = '__domo_hider_style__';
var PANEL_ID = '__domo_floating_panel__';

// ── State ──
var selectors = [];
try { selectors = JSON.parse(localStorage.getItem(STORAGE_KEY) || '[]'); } catch(e) { selectors = []; }
var hideMode = false;
var panelOpen = false;
var panelHost = null;
var panelShadow = null;

// ── CSS Injection ──
function applyCSS() {
  var el = document.getElementById(STYLE_ID);
  if (!el) {
    el = document.createElement('style');
    el.id = STYLE_ID;
    (document.head || document.documentElement).insertBefore(el, (document.head || document.documentElement).firstChild);
  }
  if (selectors.length === 0) { el.textContent = ''; return; }
  el.textContent = selectors.map(function(s) {
    return s.selector + ' { display: none !important; }';
  }).join('\n');
}

function save() {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(selectors));
  applyCSS();
  // Persist CSS to chrome.storage for early injection on next page load
  var css = selectors.map(function(s) { return s.selector + ' { display: none !important; }'; }).join('\n');
  api.updateCSS(css);
  if (panelOpen) renderPanel();
}

// ── Selector Computation ──
function computeSelector(el) {
  if (!(el instanceof Element)) return null;
  if (el.id && !el.id.startsWith('__domo')) return '#' + CSS.escape(el.id);
  var testId = el.getAttribute('data-testid') || el.getAttribute('data-test-id');
  if (testId) return '[data-testid="' + testId.replace(/"/g, '\\"') + '"]';
  var parts = [];
  var cur = el;
  for (var i = 0; i < 6 && cur && cur.nodeType === 1 && cur !== document.body; i++) {
    var tag = cur.tagName.toLowerCase();
    if (!tag) break;
    var parent = cur.parentElement;
    if (!parent) { parts.unshift(tag); break; }
    var siblings = Array.from(parent.children).filter(function(c) { return c.tagName === cur.tagName; });
    var idx = siblings.indexOf(cur) + 1;
    var piece = siblings.length > 1 ? tag + ':nth-of-type(' + idx + ')' : tag;
    parts.unshift(piece);
    if (parent.id && !parent.id.startsWith('__domo')) {
      parts.unshift('#' + CSS.escape(parent.id));
      break;
    }
    cur = parent;
  }
  return parts.join(' > ');
}

// ── Element Picker ──
function pickElement() {
  return new Promise(function(resolve) {
    var active = true;
    var overlay = document.createElement('div');
    overlay.style.cssText = 'position:fixed;inset:0;z-index:2147483646;cursor:crosshair;background:rgba(0,0,0,0.02);pointer-events:none;';
    var highlight = document.createElement('div');
    highlight.style.cssText = 'position:fixed;z-index:2147483647;pointer-events:none;border:2px solid #ff4d4f;border-radius:6px;box-shadow:0 0 0 4px rgba(255,77,79,.15);';
    function isOurUI(el) {
      while (el) {
        if (el.id && (el.id.startsWith('__domo') || el.getAttribute && el.getAttribute('data-domo'))) return true;
        el = el.parentElement;
      }
      return false;
    }
    function cleanup() {
      active = false;
      overlay.remove();
      highlight.remove();
      document.documentElement.style.cursor = '';
      window.removeEventListener('keydown', onKey, true);
      document.removeEventListener('mousemove', onMove, true);
      document.removeEventListener('click', onClick, true);
    }
    function onKey(e) {
      if (e.key === 'Escape') { e.preventDefault(); e.stopPropagation(); cleanup(); resolve(null); }
    }
    function onMove(e) {
      if (!active) return;
      var el = document.elementFromPoint(e.clientX, e.clientY);
      if (!el || isOurUI(el)) return;
      var r = el.getBoundingClientRect();
      highlight.style.left = Math.max(0, r.left) + 'px';
      highlight.style.top = Math.max(0, r.top) + 'px';
      highlight.style.width = Math.max(0, r.width) + 'px';
      highlight.style.height = Math.max(0, r.height) + 'px';
    }
    function onClick(e) {
      if (!active) return;
      e.preventDefault();
      e.stopPropagation();
      var el = document.elementFromPoint(e.clientX, e.clientY);
      if (!el || isOurUI(el)) return;
      cleanup();
      resolve(el);
    }
    document.body.appendChild(overlay);
    document.body.appendChild(highlight);
    document.documentElement.style.cursor = 'crosshair';
    window.addEventListener('keydown', onKey, true);
    document.addEventListener('mousemove', onMove, true);
    document.addEventListener('click', onClick, true);
  });
}

// ── Hide Mode ──
async function enterHideMode() {
  if (hideMode) return;
  hideMode = true;
  if (panelOpen) renderPanel();
  while (hideMode) {
    var el = await pickElement();
    if (!el) { hideMode = false; if (panelOpen) renderPanel(); return; }
    var selector = computeSelector(el);
    if (!selector) continue;
    var label = el.tagName.toLowerCase();
    if (el.className && typeof el.className === 'string') label += '.' + el.className.split(' ')[0];
    if (!selectors.some(function(s) { return s.selector === selector; })) {
      selectors.push({ selector: selector, label: label, addedAt: new Date().toISOString() });
      save();
    }
  }
}

function exitHideMode() {
  hideMode = false;
  if (panelOpen) renderPanel();
}

// ── Floating Panel ──
function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function openPanel() {
  if (panelHost) closePanel();
  panelOpen = true;
  panelHost = document.createElement('div');
  panelHost.id = PANEL_ID;
  panelHost.style.cssText = 'all:initial;position:fixed;bottom:16px;right:16px;z-index:2147483645;';
  panelShadow = panelHost.attachShadow({ mode: 'closed' });
  renderPanel();
  document.body.appendChild(panelHost);
  api.addEventListener(document, 'keydown', function(e) {
    if (e.key === 'Escape' && panelOpen && !hideMode) { e.stopPropagation(); closePanel(); }
  });
}

function closePanel() {
  panelOpen = false;
  if (panelHost) { panelHost.remove(); panelHost = null; panelShadow = null; }
}

function renderPanel() {
  if (!panelShadow) return;
  var css = '* {box-sizing:border-box;margin:0;padding:0} ' +
    '.panel {width:320px;max-height:60vh;overflow:hidden;display:flex;flex-direction:column;background:#161b22;border:1px solid #30363d;border-radius:12px;font:13px/1.5 -apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,sans-serif;color:#c9d1d9;box-shadow:0 8px 32px rgba(0,0,0,.4)} ' +
    '.hdr {display:flex;align-items:center;gap:8px;padding:10px 14px;border-bottom:1px solid #21262d} ' +
    '.title {font-weight:700;font-size:13px;color:#e6edf3} .sub {font-size:11px;color:#8b949e;margin-left:auto} ' +
    '.x {background:none;border:none;color:#8b949e;font-size:18px;cursor:pointer;padding:0 4px;line-height:1;margin-left:4px} .x:hover {color:#e6edf3} ' +
    '.body {padding:12px 14px;overflow-y:auto;max-height:calc(60vh - 44px)} ' +
    '.btn {padding:6px 12px;border-radius:6px;border:1px solid #30363d;background:#21262d;color:#c9d1d9;font:inherit;font-size:12px;font-weight:600;cursor:pointer} .btn:hover {background:#30363d} ' +
    '.bp {background:#238636;border-color:#238636;color:#fff;width:100%;margin-bottom:10px} .bp:hover {background:#2ea043} ' +
    '.bd {background:rgba(248,81,73,.1);border-color:#da3633;color:#f85149} .bd:hover {background:rgba(248,81,73,.2)} ' +
    '.bs {padding:3px 8px;font-size:11px} ' +
    '.list {display:flex;flex-direction:column;gap:4px} ' +
    '.item {display:flex;align-items:center;justify-content:space-between;gap:8px;padding:6px 8px;background:#0d1117;border:1px solid #21262d;border-radius:6px} ' +
    '.info {display:flex;flex-direction:column;gap:2px;overflow:hidden;flex:1} ' +
    '.lbl {font-size:12px;color:#c9d1d9;overflow:hidden;text-overflow:ellipsis;white-space:nowrap} ' +
    'code {font-size:11px;color:#79c0ff;background:rgba(56,139,253,.1);padding:1px 5px;border-radius:4px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;max-width:200px;display:block} ' +
    '.empty {text-align:center;padding:12px;color:#484f58;font-size:12px}';
  var items = '';
  if (selectors.length === 0) {
    items = '<div class="empty">No hidden elements on ' + esc(hostname) + '.</div>';
  } else {
    items = '<div class="list">' + selectors.map(function(s, i) {
      return '<div class="item"><div class="info">' +
        (s.label ? '<span class="lbl">' + esc(s.label) + '</span>' : '') +
        '<code>' + esc(s.selector) + '</code></div>' +
        '<button class="btn bs show-btn" data-i="' + i + '">Show</button></div>';
    }).join('') + '</div>' +
    '<button class="btn bd bs" id="reset" style="margin-top:8px">Reset All</button>';
  }
  panelShadow.innerHTML = '<style>' + css + '</style>' +
    '<div class="panel"><div class="hdr">' +
    '<span class="title">Hidden Elements</span><span class="sub">' + esc(hostname) + '</span>' +
    '<button class="x" id="close">&times;</button></div>' +
    '<div class="body">' +
    '<button class="btn bp" id="hm">' + (hideMode ? 'Exit Hide Mode' : 'Hide Mode (Alt+H)') + '</button>' +
    items + '</div></div>';
  // Wire
  panelShadow.getElementById('close').onclick = closePanel;
  panelShadow.getElementById('hm').onclick = function() { if (hideMode) exitHideMode(); else enterHideMode(); };
  var rb = panelShadow.getElementById('reset');
  if (rb) rb.onclick = function() { selectors = []; save(); };
  panelShadow.querySelectorAll('.show-btn').forEach(function(btn) {
    btn.onclick = function() { selectors.splice(parseInt(btn.dataset.i), 1); save(); };
  });
}

// ── Init ──
applyCSS();
// Seed chrome.storage so early injection works on next page load
if (selectors.length > 0) {
  var _initCSS = selectors.map(function(s) { return s.selector + ' { display: none !important; }'; }).join('\n');
  api.updateCSS(_initCSS);
}

api.addEventListener(window, 'message', function(e) {
  if (!e.data || !e.data.__domo) return;
  if (e.data.type === 'domo:command' && e.data.command === 'toggle-hide-mode') {
    if (hideMode) exitHideMode(); else enterHideMode();
  }
  if (e.data.type === 'domo:openPanel' && e.data.pluginId === api.pluginId) {
    if (panelOpen) closePanel(); else openPanel();
  }
});

api.onCleanup(function() {
  hideMode = false;
  closePanel();
  var el = document.getElementById(STYLE_ID);
  if (el) el.remove();
});
